		planFile := m.nav.GetSelectedPlanFile()
		if planFile == "" {
			return m, nil
		}
		m.pendingSetStatusTask = planFile
		statuses := []string{"ready", "planning", "implementing", "reviewing", "done", "cancelled"}
		m.overlays.Show(overlay.NewPickerOverlay("set status", statuses))
